    public static function getLogo(string $version, string $color = 'currentColor', string $highlight = '#4F5B93', string $style = ''): ?string
    {
        $found = self::MAPPING[$version] ?? null;
        if (!$found) {
            return null;
        }

        $replace = [
            '{{fill}}' => $color,
            '{{highlight}}' => $highlight,
            '{{style}}' => $style,
